+            .map_err(|e| format!("pragma failed: {e}"))?;
+
+        let count: i64 = conn
+            .query_row("SELECT count(*) FROM demo", [], |r| r.get(0))
+            .map_err(|e| format!("query failed: {e}"))?;
+
+        Ok(usize::try_from(count).expect("count fits usize"))
+    }
