+    if let WalFecRecoveryOutcome::Recovered(recovered) = outcome {
+        assert_eq!(recovered.recovered_pages.len(), frame_pages.len());
+        for (r, o) in recovered.recovered_pages.iter().zip(frame_pages.iter()) {
